import { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { SignInForm } from '../components/Auth/SignInForm';
import { SignUpForm } from '../components/Auth/SignUpForm';
import { CheckInCodeInput } from '../components/Points/CheckInCodeInput';
import { supabase } from '../lib/supabase';
import { EventCard } from '../components/Event/EventCard';
import { useEvents } from '../hooks/useEvents';

export function Home() {
  const { user } = useAuth();
  const [showSignUp, setShowSignUp] = useState(false);
  const [userName, setUserName] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const { events, loading: eventsLoading, error: eventsError } = useEvents();

  useEffect(() => {
    const fetchUserName = async () => {
      if (!user) {
        setLoading(false);
        return;
      }

      try {
        const { data: profile, error } = await supabase
          .from('user_profiles')
          .select('first_name, last_name')
          .eq('id', user.id)
          .single();

        if (error) {
          console.error('Error fetching user profile:', error);
          return;
        }

        if (profile) {
          setUserName(`${profile.first_name || ''} ${profile.last_name || ''}`.trim() || 'there');
        }
      } catch (err) {
        console.error('Error fetching user name:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchUserName();
  }, [user]);

  if (loading) return (
    <div className="min-h-screen flex items-center justify-center bg-gray-950">
      <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-500"></div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-950 text-white pb-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-6">
        {user ? (
          <div className="space-y-8">
            {/* Welcome Section */}
            <div className="relative rounded-2xl p-8 overflow-hidden"
              style={{
                background: 'linear-gradient(135deg, #2D3748 0%, #1A202C 100%)',
                backgroundImage: 'url(/images/waves-bg.svg)',
                backgroundSize: 'cover',
                backgroundPosition: 'center',
              }}
            >
              <div className="absolute inset-0 bg-gradient-to-r from-blue-500/10 to-purple-500/10 opacity-70"></div>
              <div className="relative z-10 flex items-center justify-between">
                <div>
                  <p className="text-gray-300 text-lg mb-2">June 11, 2025</p>
                  <h1 className="text-5xl font-extrabold text-white mb-4">
                    Welcome to VSA, {userName || 'there'}!
                  </h1>
                </div>
                <img src="/public/images/vsa-logo.jpg" alt="VSALogo" className="h-40 w-auto" />
              </div>
            </div>

            {/* Event Check-in Section - Moved to center */}
            <div className="max-w-md mx-auto">
              <div className="bg-gray-800 rounded-2xl shadow-xl p-6">
                <h2 className="text-2xl font-bold text-white mb-4">Event Check-in</h2>
                <CheckInCodeInput />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {/* Your Progress Section */}
              <div className="bg-gray-800 rounded-2xl shadow-xl p-6">
                <h2 className="text-2xl font-bold text-white mb-4">Your Progress</h2>
                <div className="text-gray-300 mb-2">Level 2: Exponential Eclair</div>
                <div className="w-full bg-gray-700 rounded-full h-2.5 mb-4">
                  <div className="bg-indigo-500 h-2.5 rounded-full" style={{ width: '0%' }}></div>
                </div>
                <p className="text-gray-400 text-sm">You need 100 more points to level up to <span className="font-semibold text-white">Polynomial Pita</span></p>
              </div>

              {/* Upcoming Events Section (Placeholder for consistent grid layout) */}
              <div className="bg-gray-800 rounded-2xl shadow-xl p-6">
                <h2 className="text-2xl font-bold text-white mb-4">Upcoming Events</h2>
                <p className="text-gray-400">This section will be detailed below.</p>
              </div>
            </div>

            {/* Full-width Upcoming Events Section (actual events display) */}
            <div className="bg-gray-800 rounded-2xl shadow-xl p-6">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-white">Upcoming Events</h2>
                <a href="/events" className="text-indigo-400 hover:text-indigo-300 transition-colors duration-200">
                  See all events &gt;
                </a>
              </div>
              {eventsLoading ? (
                <div className="flex justify-center">
                  <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-500"></div>
                </div>
              ) : eventsError ? (
                <div className="text-center text-red-400 bg-red-900/20 p-4 rounded-lg">
                  Error loading events: {eventsError.message}
                </div>
              ) : events.length === 0 ? (
                <div className="bg-gray-700 rounded-lg p-6 text-center">
                  <p className="text-gray-400 text-xl">Check back soon for upcoming events!</p>
                  <div className="mt-4 flex justify-center space-x-4">
                    <img src="/images/character1.svg" alt="Character 1" className="h-16 w-auto" />
                    <img src="/images/character2.svg" alt="Character 2" className="h-16 w-auto" />
                  </div>
                </div>
              ) : (
                <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                  {events
                    .slice()
                    .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
                    .map(event => (
                      <EventCard
                        key={event.id}
                        event={event}
                        onCheckIn={() => {}}
                      />
                    ))}
                </div>
              )}
            </div>
          </div>
        ) : (
          <div className="max-w-2xl mx-auto py-12">
            <div className="text-center mb-12">
              <h1 className="text-4xl font-bold text-white mb-4">
                Welcome to VSA
              </h1>
              <p className="text-xl text-gray-300">
                Sign in or create an account to start earning points and participating in events.
              </p>
            </div>
            <div className="bg-gray-800 rounded-2xl shadow-xl p-8">
              {showSignUp ? (
                <>
                  <SignUpForm />
                  <p className="mt-6 text-center text-gray-400">
                    Already have an account?{' '}
                    <button
                      onClick={() => setShowSignUp(false)}
                      className="text-indigo-400 hover:text-indigo-300 font-medium transition-colors duration-200"
                    >
                      Sign In
                    </button>
                  </p>
                </>
              ) : (
                <>
                  <SignInForm />
                  <p className="mt-6 text-center text-gray-400">
                    Don't have an account?{' '}
                    <button
                      onClick={() => setShowSignUp(true)}
                      className="text-indigo-400 hover:text-indigo-300 font-medium transition-colors duration-200"
                    >
                      Sign Up
                    </button>
                  </p>
                </>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
